// Extrae el texto del CSV del payload que manda Cowork, sea cual sea la forma
// en que n8n lo haya envuelto (varia segun version).
// Cowork deberia mandar POST con JSON: { "csv_text": "...todo el contenido del csv..." }
const j = $input.first().json;

let raw = null;
if (j.body && typeof j.body === 'object' && j.body.csv_text) raw = j.body.csv_text;
else if (j.csv_text) raw = j.csv_text;
else if (typeof j.body === 'string') raw = j.body;
else if (typeof j === 'string') raw = j;

if (!raw) {
  throw new Error('No encontre csv_text en el payload del webhook. Mira el JSON crudo de este nodo (deberia estar en json.body) y ajusta esta linea.');
}

const text = raw;
const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
if (lines.length < 2) {
  return [];
}
const headers = lines[0].split(';').map(h => h.trim());

const rows = lines.slice(1).map(line => {
  const cols = line.split(';');
  const obj = {};
  headers.forEach((h, i) => { obj[h] = cols[i] !== undefined ? cols[i].trim() : null; });
  return obj;
});

return rows.map(r => ({ json: r }));

// Arma un unico INSERT ... ON CONFLICT DO NOTHING con todas las filas del dia,
// usando SOURCE_ID como clave de idempotencia (evita duplicar si Cowork reintenta o corre dos veces).
const items = $input.all();

if (items.length === 0) {
  return [{ json: { query: 'SELECT 1;', note: 'Sin movimientos en el CSV recibido.' } }];
}

const esc = v => (v === null || v === undefined || v === '') ? 'NULL' : ("'" + String(v).replace(/'/g, "''") + "'");
const num = v => (v === null || v === undefined || v === '') ? '0' : String(v);

const values = items.map(item => {
  const r = item.json;
  return '(' + esc(r.SOURCE_ID) + ', ' + esc(r.PAYMENT_METHOD_TYPE) + ', ' + esc(r.TRANSACTION_TYPE) + ', ' +
    num(r.TRANSACTION_AMOUNT) + ', ' + esc(r.TRANSACTION_DATE) + ', ' + num(r.FEE_AMOUNT) + ', ' +
    esc(r.SETTLEMENT_DATE) + ', ' + num(r.REAL_AMOUNT) + ', ' + num(r.TAXES_AMOUNT) + ', ' +
    esc(r.BUSINESS_UNIT) + ', ' + esc(r.SUB_UNIT) + ', ' + esc(r.MONEY_RELEASE_DATE) + ')';
}).join(',\n');

const query = 'INSERT INTO mercadopago_settlements ' +
  '(source_id, payment_method_type, transaction_type, transaction_amount, transaction_date, ' +
  'fee_amount, settlement_date, real_amount, taxes_amount, business_unit, sub_unit, money_release_date) ' +
  'VALUES\n' + values + '\nON CONFLICT (source_id) DO NOTHING ' +
  'RETURNING source_id;';

return [{ json: { query, filas_recibidas: items.length } }];
